import json
import os
from e2b import Sandbox


def run_or_raise(sandbox: Sandbox, command: str) -> None:
    result = sandbox.commands.run(command)
    if result.exit_code != 0:
        raise RuntimeError(
            f"Command failed ({result.exit_code}): {command}\n{result.stderr}"
        )


def main() -> None:
    sandbox = Sandbox(timeout=600)

    try:
        run_or_raise(
            sandbox,
            "curl -LsSf https://astral.sh/uv/install.sh | sh",
        )

        uv_path = 'export PATH="$HOME/.local/bin:$PATH"'
        run_or_raise(sandbox, f"{uv_path} && uv venv /home/user/venv")
        run_or_raise(
            sandbox,
            f"{uv_path} && uv pip -p /home/user/venv install pandas numpy",
        )
        run_or_raise(
            sandbox,
            f"{uv_path} && /home/user/venv/bin/python -c \"import pandas as pd; print(pd.__version__)\" > /home/user/pandas_version.txt",
        )

        sandbox_info = {"sandbox_id": sandbox.id}
        with open("/home/user/e2b_task_info.json", "w", encoding="utf-8") as file:
            json.dump(sandbox_info, file)
    finally:
        pass


if __name__ == "__main__":
    if "E2B_API_KEY" not in os.environ:
        raise EnvironmentError("E2B_API_KEY is not set in the environment")
    main()
